import math
class Solution:
    def sumOfAncestors(self, n, edges, nums):
        from collections import deque
        g = [[] for _ in range(n)]
        for u, v in edges:
            g[u].append(v)
            g[v].append(u)
        par = [-1] * n
        seen = [False] * n
        seen[0] = True
        q = deque([0])
        while q:
            u = q.popleft()
            for w in g[u]:
                if not seen[w]:
                    seen[w] = True
                    par[w] = u
                    q.append(w)
        def is_sq(x):
            r = math.isqrt(x)
            return r * r == x
        total = 0
        for i in range(1, n):
            a = par[i]
            while a != -1:
                if is_sq(nums[i] * nums[a]):
                    total += 1
                a = par[a]
        return total

