class Solution:
    def sumOfAncestors(self, n, edges, nums):
        def squarefree(x):
            res = 1
            d = 2
            while d * d <= x:
                if x % d == 0:
                    c = 0
                    while x % d == 0:
                        x //= d
                        c += 1
                    if c % 2:
                        res *= d
                d += 1
            if x > 1:
                res *= x
            return res
        g = [[] for _ in range(n)]
        for u, v in edges:
            g[u].append(v)
            g[v].append(u)
        sf = [squarefree(x) for x in nums]
        from collections import defaultdict
        cnt = defaultdict(int)
        total = 0
        stack = [(0, -1, False)]
        while stack:
            u, p, post = stack.pop()
            if post:
                cnt[sf[u]] -= 1
                continue
            if u != 0:
                total += cnt[sf[u]]
            cnt[sf[u]] += 1
            stack.append((u, p, True))
            for w in g[u]:
                if w != p:
                    stack.append((w, u, False))
        return total

