var sumOfAncestors = function(n, edges, nums) {
    const squarefree = (x) => {
        let res = 1;
        for (let d = 2; d * d <= x; d++) {
            if (x % d === 0) {
                let c = 0;
                while (x % d === 0) { x = Math.floor(x / d); c++; }
                if (c % 2) res *= d;
            }
        }
        if (x > 1) res *= x;
        return res;
    };
    const g = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) { g[u].push(v); g[v].push(u); }
    const sf = nums.map(squarefree);
    const cnt = new Map();
    let total = 0;
    const stack = [[0, -1, false]];
    while (stack.length) {
        const [u, p, post] = stack.pop();
        if (post) {
            cnt.set(sf[u], cnt.get(sf[u]) - 1);
            continue;
        }
        if (u !== 0) total += cnt.get(sf[u]) || 0;
        cnt.set(sf[u], (cnt.get(sf[u]) || 0) + 1);
        stack.push([u, p, true]);
        for (const w of g[u]) {
            if (w !== p) stack.push([w, u, false]);
        }
    }
    return total;
};
